// 通信架构的 ADT 封装接口定义

/* 消息队列适配器 —— 封装 xQueueCreate / xQueueSend / xQueueReceive */
#define SENSOR_QUEUE_DEPTH   8
#define SENSOR_MSG_SIZE      sizeof(SensorReading_t)

typedef struct {
    float temperature;
    float humidity;
    uint32_t timestamp_ms;
} SensorReading_t;

/* 模块内部静态变量 —— 信息隐藏 */
static QueueHandle_t xSensorQueue;

BaseType_t CommQueue_Init(void) {
    xSensorQueue = xQueueCreate(SENSOR_QUEUE_DEPTH, SENSOR_MSG_SIZE);
    return (xSensorQueue != NULL) ? pdPASS : pdFAIL;
}

BaseType_t CommQueue_Put(const SensorReading_t *msg, TickType_t ticks) {
    return xQueueSend(xSensorQueue, msg, ticks);
}

BaseType_t CommQueue_Get(SensorReading_t *msg, TickType_t ticks) {
    return xQueueReceive(xSensorQueue, msg, ticks);
}

/* 队列深度：最大帧 128 字节 × 2 倍余量 */
#define UART_RX_QUEUE_DEPTH  2
#define UART_FRAME_SIZE      128

static QueueHandle_t xUartRxQueue;
static uint8_t uartRxBuf[UART_RX_QUEUE_SIZE];

/* 任务函数 —— 从队列取数据并解析 */
void vUartProcessorTask(void *pvParameters) {
    uint8_t frame[UART_FRAME_SIZE];
    uint32_t len;

    for (;;) {
        /* 阻塞等待，超时 100ms 做看门狗喂狗 */
        if (xQueueReceive(xUartRxQueue, &len, pdMS_TO_TICKS(100))) {
            /* 从 DMA 缓冲区复制数据 —— 值传递而非指针 */
            memcpy(frame, uartRxBuf, len);
            ParseFrame(frame, len);  /* 解析并处理 */
        } else {
            HAL_GPIO_TogglePin(WDOG_GPIO_Port, WDOG_Pin);  /* 喂狗 */
        }
    }
}

/* UART IDLE 中断回调 —— DMA 一次接收完成后调用 */
void HAL_UARTEx_RxEventCallback(UART_HandleTypeDef *huart, uint16_t Size) {
    BaseType_t xHigherPriorityTaskWoken = pdFALSE;

    /* 关键：先复制数据，再清标志 —— 因为 DMA 会继续覆盖缓冲区 */
    uint32_t xResult = xQueueSendFromISR(xUartRxQueue, &Size,
                                          &xHigherPriorityTaskWoken);

    if (xResult == pdPASS) {
        /* 如果 xHigherPriorityTaskWoken == pdTRUE，需要手动触发上下文切换 */
        portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
    }
    /* 注意：DMA 标志清除由 HAL 内部完成，此处无需手动写寄存器 */
}

/* 坑4 的正确修复 —— 用 Event Group 替代 Counting Semaphore */

/* 事件位定义 */
#define BIT_TIMER_EVT      (1 << 0)
#define BIT_UART_EVT       (1 << 1)

/* 任务等待两个事件同时到达 */
typedef struct {
    EventGroupHandle_t xEvents;
} AppContext_t;

static AppContext_t g_app;

void vAppMainTask(void *pvParameters) {
    EventBits_t bits;

    for (;;) {
        /* 等待 BIT_TIMER_EVT | BIT_UART_EVT，等待超时 1 秒 */
        bits = xEventGroupWaitBits(
            g_app.xEvents,
            BIT_TIMER_EVT | BIT_UART_EVT,
            pdFALSE,  /* 不清位 —— 两个 ISR 可以独立设置 */
            pdTRUE,   /* 等待所有位都到达 */
            pdMS_TO_TICKS(1000)
        );

        if ((bits & (BIT_TIMER_EVT | BIT_UART_EVT)) ==
            (BIT_TIMER_EVT | BIT_UART_EVT)) {
            /* 两个事件都到达了，执行业务逻辑 */
            ProcessTimedData();
        } else {
            /* 超时了 —— 1 秒内没有凑齐两个事件 */
            ResetTimeoutCounter();
        }
    }
}

/* 定时器 ISR */
void TIM6_DAC_IRQHandler(void) {
    BaseType_t xHigherPriorityTaskWoken = pdFALSE;

    if (LL_TIM_IsActiveFlag_UPDATE(TIM6)) {
        LL_TIM_ClearFlag_UPDATE(TIM6);
        xEventGroupSetBitsFromISR(g_app.xEvents,
                                   BIT_TIMER_EVT,
                                   &xHigherPriorityTaskWoken);
        portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
    }
}

/* UART IDLE ISR */
void UART4_IRQHandler(void) {
    BaseType_t xHigherPriorityTaskWoken = pdFALSE;

    if (LL_USART_IsActiveFlag_IDLE(UART4)) {
        LL_USART_ClearFlag_IDLE(UART4);
        xEventGroupSetBitsFromISR(g_app.xEvents,
                                   BIT_UART_EVT,
                                   &xHigherPriorityTaskWoken);
        portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
    }
}

