// sensor.h
typedef struct {
    float temp;
    float hum;
    uint32_t ts;
} SensorData_t;
extern SensorData_t g_sensor_data;  // 全局变量 —— 任何文件都能读能写

// adc_isr.c
SensorData_t g_sensor_data;  // 定义

void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef *hadc) {
    /* ISR 直接写全局变量 —— 没有同步保护！ */
    g_sensor_data.temp = HAL_ADC_GetValue(hadc) * 0.001f * 3.3f * 175.0f - 45.0f;
    g_sensor_data.hum  = HAL_ADC_GetValue(&hadc2) * 0.001f * 3.3f * 100.0f;
    g_sensor_data.ts   = xTaskGetTickCount();  // ISR 里调用 RTOS API —— 可以但不好
}

// processor_task.c
void vProcessorTask(void *pvParameters) {
    for (;;) {
        float t = g_sensor_data.temp;   // 可能读到脏数据（temp 更新了但 hum 没更新）
        float h = g_sensor_data.hum;
        ProcessTemperature(t, h);
        vTaskDelay(pdMS_TO_TICKS(100));
    }
}

