// sensor_queue.h
#ifndef SENSOR_QUEUE_H
#define SENSOR_QUEUE_H

typedef struct {
    float temp;
    float hum;
    uint32_t ts;
} SensorReading_t;

BaseType_t SensorQueue_Init(void);
BaseType_t SensorQueue_Push(const SensorReading_t *reading, TickType_t timeout);

#endif

// sensor_queue.c
static QueueHandle_t xSensorQueue;

BaseType_t SensorQueue_Init(void) {
    xSensorQueue = xQueueCreate(4, sizeof(SensorReading_t));
    return (xSensorQueue != NULL) ? pdPASS : pdFAIL;
}

BaseType_t SensorQueue_Push(const SensorReading_t *reading, TickType_t timeout) {
    return xQueueSend(xSensorQueue, reading, timeout);
}

// adc_isr.c
#include "sensor_queue.h"

void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef *hadc) {
    SensorReading_t reading;
    reading.temp = HAL_ADC_GetValue(hadc) * 0.001f * 3.3f * 175.0f - 45.0f;
    reading.hum  = HAL_ADC_GetValue(&hadc2) * 0.001f * 3.3f * 100.0f;
    reading.ts   = xTaskGetTickCount();

    /* 队列满了就丢弃最旧的数据 —— 实时系统优先最新数据 */
    xQueueSend(xSensorQueue, &reading, 0);  /* timeout=0 = 非阻塞，满了直接丢 */
}

// processor_task.c
void vProcessorTask(void *pvParameters) {
    SensorReading_t reading;

    for (;;) {
        /* 阻塞等待新数据，超时 1 秒说明传感器可能挂了 */
        if (xQueueReceive(xSensorQueue, &reading, pdMS_TO_TICKS(1000))) {
            ProcessTemperature(reading.temp, reading.hum);
        } else {
            ReportSensorFault();  /* 1 秒内没有收到新数据 —— 传感器故障 */
        }
    }
}

